def fibonacci(params: dict) -> str:
    """Calculate fibonacci using fast doubling method. O(log n)."""
    try:
        n = int(params.get("n", 0))
        if n < 0:
            return "0"
        if n <= 1:
            return str(n)

        def fib_pair(k):
            """Return (F(k), F(k+1)) using fast doubling."""
            if k == 0:
                return (0, 1)
            a, b = fib_pair(k >> 1)
            c = a * (2 * b - a)
            d = a * a + b * b
            if k & 1:
                return (d, c + d)
            else:
                return (c, d)

        return str(fib_pair(n)[0])
    except (ValueError, TypeError):
        return "0"
